# --- Arduino / İlkokul ---
add("arduino","ilkokul","Arduino'da LED nedir ve nasıl yanar?","LED (Light Emitting Diode) küçük bir ışık kaynağıdır. Arduino'da bir LED yakmak için:\n\n1. LED'in uzun bacağını (anot, +) Arduino'nun dijital pinine bağla\n2. Kısa bacağını (katot, -) bir direnç üzerinden GND'ye bağla\n3. Kodda `digitalWrite(pin, HIGH)` yazarak LED'i yakabilirsin\n\nLED'in önüne her zaman 220Ω direnç koy, yoksa LED yanabilir!")

add("arduino","ilkokul","Arduino nedir ve ne işe yarar?","Arduino, küçük bir bilgisayar kartıdır. Sensörlerden bilgi okuyabilir ve LED, motor gibi parçaları kontrol edebilir.\n\n**Ne yapabilirsin?**\n- LED yakıp söndürmek\n- Sıcaklık ölçmek\n- Robot yapmak\n- Müzik çalmak\n\nArduino'yu bilgisayarına USB kablosuyla bağlarsın, kod yazarsın ve karta yüklersin. Kart kodu çalıştırır!")

add("arduino","ilkokul","Arduino ile 3 LED'i sırayla yakıp söndüren trafik lambası yap.","Kırmızı, sarı ve yeşil LED ile trafik lambası:\n\n```cpp\nint kirmizi = 13;\nint sari = 12;\nint yesil = 11;\n\nvoid setup() {\n  pinMode(kirmizi, OUTPUT);\n  pinMode(sari, OUTPUT);\n  pinMode(yesil, OUTPUT);\n}\n\nvoid loop() {\n  // Kırmızı yan\n  digitalWrite(kirmizi, HIGH);\n  delay(3000);\n  digitalWrite(kirmizi, LOW);\n  // Sarı yan\n  digitalWrite(sari, HIGH);\n  delay(1000);\n  digitalWrite(sari, LOW);\n  // Yeşil yan\n  digitalWrite(yesil, HIGH);\n  delay(3000);\n  digitalWrite(yesil, LOW);\n}\n```\n\nHer LED sırayla yanar. Kırmızı 3 saniye, sarı 1 saniye, yeşil 3 saniye yanar.")

add("arduino","ilkokul","Arduino'da buton nasıl kullanılır?","Butona basınca LED yakan basit devre:\n\n```cpp\nint butonPin = 7;\nint ledPin = 13;\n\nvoid setup() {\n  pinMode(butonPin, INPUT_PULLUP);\n  pinMode(ledPin, OUTPUT);\n}\n\nvoid loop() {\n  if (digitalRead(butonPin) == LOW) {\n    digitalWrite(ledPin, HIGH);\n  } else {\n    digitalWrite(ledPin, LOW);\n  }\n}\n```\n\n**INPUT_PULLUP** butonu ters çalıştırır: basılınca LOW, bırakılınca HIGH olur. Bu sayede ekstra direnç gerekmez.")

add("arduino","ilkokul","Arduino'da buzzer ile melodi çalmak nasıl yapılır?","Buzzer ile basit bir melodi:\n\n```cpp\nint buzzer = 8;\n\nvoid setup() {\n  pinMode(buzzer, OUTPUT);\n}\n\nvoid loop() {\n  tone(buzzer, 262, 500); // Do notası\n  delay(600);\n  tone(buzzer, 294, 500); // Re notası\n  delay(600);\n  tone(buzzer, 330, 500); // Mi notası\n  delay(600);\n  tone(buzzer, 349, 500); // Fa notası\n  delay(600);\n  noTone(buzzer);\n  delay(2000);\n}\n```\n\n`tone(pin, frekans, süre)` fonksiyonu ses çıkarır. Frekans ne kadar yüksekse ses o kadar ince olur.")

add("arduino","ilkokul","Arduino'daki dijital ve analog pinler arasındaki fark nedir?","**Dijital pinler** sadece iki durum bilir: AÇIK (HIGH = 5V) veya KAPALI (LOW = 0V). Işık anahtarı gibi düşün.\n\n**Analog pinler** (A0-A5) ise 0 ile 1023 arasında değer okuyabilir. Ses seviyesi ayarı gibi düşün — kısık, orta veya yüksek olabilir.\n\n**Örnek:**\n- Dijital: LED yak/söndür, butona basıldı mı?\n- Analog: Sıcaklık kaç derece? Işık ne kadar parlak?")

# --- Arduino / Ortaokul ---
add("arduino","ortaokul","Arduino ile potansiyometre kullanarak LED parlaklığını ayarla.","Potansiyometre analog bir değer üretir, bunu LED parlaklığına çevirebiliriz:\n\n```cpp\nint potPin = A0;\nint ledPin = 9; // PWM destekli pin\n\nvoid setup() {\n  pinMode(ledPin, OUTPUT);\n}\n\nvoid loop() {\n  int potDeger = analogRead(potPin);    // 0-1023\n  int parlaklik = map(potDeger, 0, 1023, 0, 255); // 0-255'e dönüştür\n  analogWrite(ledPin, parlaklik);\n  delay(10);\n}\n```\n\n**Açıklama:**\n- `analogRead()` potansiyometreden 0-1023 arası değer okur\n- `map()` bu değeri 0-255 arasına dönüştürür\n- `analogWrite()` PWM ile LED parlaklığını ayarlar\n- PWM destekli pinler: 3, 5, 6, 9, 10, 11 (~ işaretli)")

add("arduino","ortaokul","Arduino ile LDR (ışık sensörü) kullanarak karanlıkta otomatik yanan LED yap.","LDR ışık miktarına göre direnç değiştirir:\n\n```cpp\nint ldrPin = A0;\nint ledPin = 13;\nint esikDeger = 500;\n\nvoid setup() {\n  pinMode(ledPin, OUTPUT);\n  Serial.begin(9600);\n}\n\nvoid loop() {\n  int isikDeger = analogRead(ldrPin);\n  Serial.println(isikDeger);\n  \n  if (isikDeger < esikDeger) {\n    digitalWrite(ledPin, HIGH); // Karanlık → LED yak\n  } else {\n    digitalWrite(ledPin, LOW);  // Aydınlık → LED söndür\n  }\n  delay(100);\n}\n```\n\n**Devre:** LDR'nin bir ucu 5V'a, diğer ucu hem A0'a hem de 10kΩ direnç üzerinden GND'ye bağlanır (gerilim bölücü).")

add("arduino","ortaokul","Arduino ile servo motor kontrolü nasıl yapılır?","Servo motor 0-180 derece arasında döner:\n\n```cpp\n#include <Servo.h>\n\nServo servoMotor;\n\nvoid setup() {\n  servoMotor.attach(9); // Servo pin 9'a bağlı\n}\n\nvoid loop() {\n  servoMotor.write(0);    // 0 dereceye git\n  delay(1000);\n  servoMotor.write(90);   // 90 dereceye git\n  delay(1000);\n  servoMotor.write(180);  // 180 dereceye git\n  delay(1000);\n}\n```\n\n**Bağlantı:**\n- Turuncu kablo → Dijital pin (9)\n- Kırmızı kablo → 5V\n- Kahverengi kablo → GND\n\n**İpucu:** `Servo.h` kütüphanesi Arduino IDE ile birlikte gelir, ekstra kurulum gerekmez.")

add("arduino","ortaokul","Arduino ile HC-SR04 ultrasonik mesafe sensörü nasıl kullanılır?","HC-SR04 ses dalgası göndererek mesafe ölçer:\n\n```cpp\nint trigPin = 9;\nint echoPin = 10;\n\nvoid setup() {\n  pinMode(trigPin, OUTPUT);\n  pinMode(echoPin, INPUT);\n  Serial.begin(9600);\n}\n\nvoid loop() {\n  // Ses dalgası gönder\n  digitalWrite(trigPin, LOW);\n  delayMicroseconds(2);\n  digitalWrite(trigPin, HIGH);\n  delayMicroseconds(10);\n  digitalWrite(trigPin, LOW);\n  \n  // Geri dönüş süresini ölç\n  long sure = pulseIn(echoPin, HIGH);\n  float mesafe = sure * 0.034 / 2; // cm cinsinden\n  \n  Serial.print(\"Mesafe: \");\n  Serial.print(mesafe);\n  Serial.println(\" cm\");\n  delay(500);\n}\n```\n\n**Nasıl çalışır:** Trig pini ultrasonik ses gönderir, Echo pini geri dönen sesi algılar. Süreyi mesafeye çevirmek için ses hızını (340 m/s) kullanırız.")

add("arduino","ortaokul","Arduino ile RGB LED kullanarak farklı renkler oluştur.","RGB LED içinde kırmızı, yeşil ve mavi LED bulunur:\n\n```cpp\nint kirmizi = 11;\nint yesil = 10;\nint mavi = 9;\n\nvoid setup() {\n  pinMode(kirmizi, OUTPUT);\n  pinMode(yesil, OUTPUT);\n  pinMode(mavi, OUTPUT);\n}\n\nvoid renkAyarla(int r, int g, int b) {\n  analogWrite(kirmizi, r);\n  analogWrite(yesil, g);\n  analogWrite(mavi, b);\n}\n\nvoid loop() {\n  renkAyarla(255, 0, 0);   // Kırmızı\n  delay(1000);\n  renkAyarla(0, 255, 0);   // Yeşil\n  delay(1000);\n  renkAyarla(0, 0, 255);   // Mavi\n  delay(1000);\n  renkAyarla(255, 255, 0); // Sarı\n  delay(1000);\n  renkAyarla(255, 0, 255); // Mor\n  delay(1000);\n  renkAyarla(0, 255, 255); // Turkuaz\n  delay(1000);\n}\n```\n\n**Renk karışımı:** Her renk 0-255 arası ayarlanır. Üç rengin karışımıyla 16 milyondan fazla renk elde edebilirsin!")

add("arduino","ortaokul","Arduino ile Serial Monitor kullanarak bilgisayarla haberleşme nasıl yapılır?","Serial Monitor, Arduino'dan bilgisayara veri göndermeye yarar:\n\n```cpp\nvoid setup() {\n  Serial.begin(9600); // Haberleşme hızı\n  Serial.println(\"Arduino hazir!\");\n}\n\nvoid loop() {\n  if (Serial.available() > 0) {\n    String mesaj = Serial.readString();\n    Serial.print(\"Gonderdin: \");\n    Serial.println(mesaj);\n    \n    if (mesaj == \"merhaba\") {\n      Serial.println(\"Selam! Ben Arduino.\");\n    }\n  }\n}\n```\n\n**Kullanım:**\n1. Kodu yükle\n2. Araçlar → Serial Monitor aç\n3. Üst kutuya mesaj yaz ve Gönder'e bas\n4. Arduino cevap verecek\n\n**9600** baud rate'tir — Arduino ve bilgisayar aynı hızda konuşmalı.")

add("arduino","ortaokul","Arduino ile su seviyesi sensörü kullanarak akvaryum su seviyesi alarmı yap.","Su seviyesi sensörü suyun yüksekliğine göre analog değer verir:\n\n```cpp\nint suSensor = A0;\nint buzzer = 8;\nint ledKirmizi = 13;\nint esik = 300; // Su seviyesi eşiği\n\nvoid setup() {\n  pinMode(buzzer, OUTPUT);\n  pinMode(ledKirmizi, OUTPUT);\n  Serial.begin(9600);\n}\n\nvoid loop() {\n  int seviye = analogRead(suSensor);\n  Serial.print(\"Su seviyesi: \");\n  Serial.println(seviye);\n  \n  if (seviye < esik) {\n    // Su az - alarm ver\n    digitalWrite(ledKirmizi, HIGH);\n    tone(buzzer, 1000, 500);\n    Serial.println(\"UYARI: Su seviyesi dusuk!\");\n  } else {\n    digitalWrite(ledKirmizi, LOW);\n    noTone(buzzer);\n  }\n  delay(1000);\n}\n```\n\nSensör suya ne kadar batarsa o kadar yüksek değer verir. Eşik değerini kendi akvaryumuna göre ayarla.")

add("arduino","ortaokul","Arduino'da for döngüsü ile LED animasyonu nasıl yapılır?","8 LED'i sırayla yakıp söndüren Knight Rider efekti:\n\n```cpp\nint ledPinleri[] = {2,3,4,5,6,7,8,9};\nint ledSayisi = 8;\n\nvoid setup() {\n  for (int i = 0; i < ledSayisi; i++) {\n    pinMode(ledPinleri[i], OUTPUT);\n  }\n}\n\nvoid loop() {\n  // Soldan sağa\n  for (int i = 0; i < ledSayisi; i++) {\n    digitalWrite(ledPinleri[i], HIGH);\n    delay(100);\n    digitalWrite(ledPinleri[i], LOW);\n  }\n  // Sağdan sola\n  for (int i = ledSayisi - 2; i > 0; i--) {\n    digitalWrite(ledPinleri[i], HIGH);\n    delay(100);\n    digitalWrite(ledPinleri[i], LOW);\n  }\n}\n```\n\n**for döngüsü yapısı:** `for (başlangıç; koşul; artış)` — koşul doğru olduğu sürece tekrarlar.")

add("arduino","ortaokul","Arduino ile IR (kızılötesi) kumanda alıcısı nasıl kullanılır?","TV kumandası ile LED kontrol etme:\n\n```cpp\n#include <IRremote.h>\n\nint irPin = 11;\nint ledPin = 13;\nIRrecv irAlici(irPin);\ndecode_results sonuc;\n\nvoid setup() {\n  Serial.begin(9600);\n  irAlici.enableIRIn();\n  pinMode(ledPin, OUTPUT);\n}\n\nvoid loop() {\n  if (irAlici.decode(&sonuc)) {\n    Serial.println(sonuc.value, HEX);\n    \n    if (sonuc.value == 0xFFA25D) { // Kumandanın 1 tuşu\n      digitalWrite(ledPin, HIGH);\n    }\n    if (sonuc.value == 0xFF629D) { // Kumandanın 2 tuşu\n      digitalWrite(ledPin, LOW);\n    }\n    irAlici.resume();\n  }\n}\n```\n\n**Adımlar:**\n1. Önce kumandanın tuş kodlarını Serial Monitor'den oku\n2. Kodları `if` bloklarına yerleştir\n3. Her tuşa farklı aksiyon ata")

