add("mblock","ilkokul","mBot nedir ve ne yapabilir?","mBot, çocuklar için tasarlanmış bir eğitim robotudur.\n\n**mBot'un parçaları:**\n- Ana kart (mCore): Arduino tabanlı beyin\n- 2 DC motor: hareket için\n- Ultrasonik sensör: mesafe ölçer\n- Çizgi izleme sensörü: siyah çizgiyi takip eder\n- LED'ler: renkli ışıklar\n- Buzzer: ses çıkarır\n\n**mBlock ile programla:**\n- Sürükle-bırak bloklar kullanarak\n- Bilgisayardan USB veya Bluetooth ile bağlan\n- Kodunu yükle ve robotu çalıştır!")

add("mblock","ilkokul","mBot'u ileri, geri, sağa ve sola nasıl hareket ettiririm?","mBot hareket blokları:\n\n```\n[Yeşil bayrak tıklandığında]\n[İleri git, hız: 150]\n[2 saniye bekle]\n[Geri git, hız: 150]\n[2 saniye bekle]\n[Sola dön, hız: 100]\n[1 saniye bekle]\n[Sağa dön, hız: 100]\n[1 saniye bekle]\n[Dur]\n```\n\n**Hız değerleri:**\n- 0: Durur\n- 100: Yavaş\n- 150: Orta\n- 255: Maksimum hız\n\n**İpucu:** Dönme süresini değiştirerek dönüş açısını ayarlayabilirsin!")

add("mblock","ilkokul","mBot'un LED'lerini farklı renklere nasıl ayarlarım?","mBot'ta 2 adet RGB LED var:\n\n```\n[Yeşil bayrak tıklandığında]\n[LED (tümü) rengini kırmızı:(255) yeşil:(0) mavi:(0) yap]  // Kırmızı\n[2 saniye bekle]\n[LED (tümü) rengini kırmızı:(0) yeşil:(255) mavi:(0) yap]  // Yeşil\n[2 saniye bekle]\n[LED (tümü) rengini kırmızı:(0) yeşil:(0) mavi:(255) yap]  // Mavi\n[2 saniye bekle]\n[LED (tümü) rengini kırmızı:(0) yeşil:(0) mavi:(0) yap]    // Kapat\n```\n\nHer renk 0-255 arası ayarlanır. Karıştırarak yeni renkler elde edebilirsin: kırmızı+yeşil=sarı, kırmızı+mavi=mor.")

add("mblock","ortaokul","mBot ile çizgi izleyen robot nasıl programlanır?","Çizgi izleme sensörü 4 durum algılar:\n\n```\n[Yeşil bayrak tıklandığında]\n[Sürekli tekrarla]\n  [Eğer <çizgi sensörü (Port 2) değeri = 0> ise]  // İki sensör de çizgide\n    [İleri git, hız: 100]\n  [Eğer sonu]\n  [Eğer <çizgi sensörü değeri = 1> ise]  // Sağ sensör çizgi dışında\n    [Sola dön, hız: 80]\n  [Eğer sonu]\n  [Eğer <çizgi sensörü değeri = 2> ise]  // Sol sensör çizgi dışında\n    [Sağa dön, hız: 80]\n  [Eğer sonu]\n  [Eğer <çizgi sensörü değeri = 3> ise]  // İkisi de çizgi dışında\n    [Dur]\n  [Eğer sonu]\n[Tekrarla sonu]\n```\n\n**Sensör değerleri:**\n- 0: Her iki sensör çizgide\n- 1: Sol sensör çizgide, sağ dışında\n- 2: Sağ sensör çizgide, sol dışında\n- 3: Her iki sensör çizgi dışında")

add("mblock","ortaokul","mBot ile müzik çalan bir program nasıl yapılır?","mBot'un buzzer'ı ile melodi çalma:\n\n```\n[Yeşil bayrak tıklandığında]\n// Küçük Kurbağa melodisi\n[Buzzer ile (C4) notasını (0.5) vuruş çal]\n[Buzzer ile (D4) notasını (0.5) vuruş çal]\n[Buzzer ile (E4) notasını (0.5) vuruş çal]\n[Buzzer ile (C4) notasını (0.5) vuruş çal]\n[Buzzer ile (C4) notasını (0.5) vuruş çal]\n[Buzzer ile (D4) notasını (0.5) vuruş çal]\n[Buzzer ile (E4) notasını (0.5) vuruş çal]\n[Buzzer ile (C4) notasını (0.5) vuruş çal]\n[Buzzer ile (E4) notasını (0.5) vuruş çal]\n[Buzzer ile (F4) notasını (0.5) vuruş çal]\n[Buzzer ile (G4) notasını (1) vuruş çal]\n```\n\n**Nota karşılıkları:** C4=Do, D4=Re, E4=Mi, F4=Fa, G4=Sol, A4=La, B4=Si. Vuruş süresini artırarak notayı uzatabilirsin.")

add("mblock","ortaokul","mBot ile uzaktan kumandalı robot nasıl yapılır?","IR kumanda ile mBot kontrolü:\n\n```\n[Yeşil bayrak tıklandığında]\n[Sürekli tekrarla]\n  [Eğer <IR kumanda (Yukarı) tuşuna basıldı mı?> ise]\n    [İleri git, hız: 150]\n  [Eğer sonu]\n  [Eğer <IR kumanda (Aşağı) tuşuna basıldı mı?> ise]\n    [Geri git, hız: 150]\n  [Eğer sonu]\n  [Eğer <IR kumanda (Sol) tuşuna basıldı mı?> ise]\n    [Sola dön, hız: 100]\n  [Eğer sonu]\n  [Eğer <IR kumanda (Sağ) tuşuna basıldı mı?> ise]\n    [Sağa dön, hız: 100]\n  [Eğer sonu]\n  [Eğer <IR kumanda hiçbir tuşa basılmadı> ise]\n    [Dur]\n  [Eğer sonu]\n[Tekrarla sonu]\n```\n\nmBot kutusunda IR kumanda gelir. Her tuşa farklı hareket atayabilirsin.")

add("mblock","lise","mBot ile PID tabanlı hassas çizgi izleme nasıl yapılır?","mBlock'un Arduino moduna geçerek PID kontrol yaz:\n\n```cpp\n#include <MeMCore.h>\n\nMeLineFollower lineFollower(PORT_2);\nMeDCMotor motorL(M1);\nMeDCMotor motorR(M2);\n\nfloat Kp = 20, Ki = 0.1, Kd = 10;\nfloat hata, oncekiHata = 0, toplamHata = 0;\nint temelHiz = 120;\n\nvoid setup() {\n  Serial.begin(9600);\n}\n\nvoid loop() {\n  int sensor = lineFollower.readSensors();\n  \n  switch(sensor) {\n    case 0: hata = 0; break;    // Çizgide\n    case 1: hata = -1; break;   // Sola sapma\n    case 2: hata = 1; break;    // Sağa sapma\n    case 3: hata = oncekiHata * 2; break; // Kayıp\n  }\n  \n  toplamHata += hata;\n  toplamHata = constrain(toplamHata, -50, 50);\n  float duzeltme = Kp*hata + Ki*toplamHata + Kd*(hata-oncekiHata);\n  oncekiHata = hata;\n  \n  motorL.run(temelHiz + duzeltme);\n  motorR.run(temelHiz - duzeltme);\n}\n```\n\nPID ile robot çizgiyi çok daha yumuşak ve hızlı takip eder.")

