add("mblock","lise","mBot'u Arduino modunda programlayarak Bluetooth ile kontrol et.","mBlock Arduino moduna geçerek C++ kodu:\n\n```cpp\n#include <MeMCore.h>\n\nMeBluetooth bluetooth(PORT_0);\nMeDCMotor motorL(M1);\nMeDCMotor motorR(M2);\n\nvoid setup() {\n  bluetooth.begin(9600);\n}\n\nvoid loop() {\n  if (bluetooth.available()) {\n    char komut = bluetooth.read();\n    switch(komut) {\n      case 'F': motorL.run(150); motorR.run(150); break;\n      case 'B': motorL.run(-150); motorR.run(-150); break;\n      case 'L': motorL.run(-100); motorR.run(100); break;\n      case 'R': motorL.run(100); motorR.run(-100); break;\n      case 'S': motorL.run(0); motorR.run(0); break;\n    }\n  }\n}\n```\n\nTelefondaki Bluetooth terminal uygulamasından F/B/L/R/S harfleri göndererek robotu kontrol edebilirsin.")

add("mblock","lise","mBot ile encoder motor kullanarak hassas mesafe kontrolü nasıl yapılır?","Encoder motor ile belirli mesafe ilerletme:\n\n```cpp\n#include <MeMCore.h>\n#include <MeEncoderMotor.h>\n\nMeEncoderMotor motorL(SLOT_1);\nMeEncoderMotor motorR(SLOT_2);\n\nvoid setup() {\n  motorL.begin();\n  motorR.begin();\n  Serial.begin(9600);\n}\n\nvoid ileriGit(float cm) {\n  // mBot tekerlek çevresi ~20cm\n  float derece = (cm / 20.0) * 360.0;\n  motorL.moveTo(derece, 150);\n  motorR.moveTo(derece, 150);\n  delay(cm * 50);\n}\n\nvoid don(float aci) {\n  float derece = (aci / 360.0) * 800;\n  motorL.moveTo(derece, 100);\n  motorR.moveTo(-derece, 100);\n  delay(aci * 10);\n}\n\nvoid loop() {\n  ileriGit(30);  // 30cm ilerle\n  delay(500);\n  don(90);       // 90 derece dön\n  delay(500);\n}\n```\n\nEncoder sayesinde tekerlek dönüşünü sayarak hassas mesafe ve açı kontrolü yapabilirsin.")

add("mblock","lise","mBot ile sensör füzyonu kullanarak akıllı engelden kaçma nasıl yapılır?","Ultrasonik + çizgi sensörünü birlikte kullanma:\n\n```cpp\n#include <MeMCore.h>\n\nMeUltrasonicSensor ultra(PORT_3);\nMeLineFollower line(PORT_2);\nMeDCMotor motorL(M1);\nMeDCMotor motorR(M2);\nMeRGBLed led(0, 2);\n\nvoid setup() {\n  Serial.begin(9600);\n}\n\nvoid loop() {\n  float mesafe = ultra.distanceCm();\n  int cizgi = line.readSensors();\n  \n  // Öncelik 1: Uçurum algılama (çizgi sensörü)\n  if (cizgi == 3) {  // İki sensör de beyaz = uçurum\n    motorL.run(-120);\n    motorR.run(-120);\n    led.setColor(0, 255, 0, 0);  // Kırmızı\n    led.show();\n    delay(500);\n    motorL.run(120);\n    motorR.run(-120);\n    delay(400);\n  }\n  // Öncelik 2: Engel algılama\n  else if (mesafe < 25 && mesafe > 0) {\n    motorL.run(0);\n    motorR.run(0);\n    led.setColor(0, 255, 255, 0);  // Sarı\n    led.show();\n    delay(200);\n    motorL.run(-100);\n    motorR.run(100);\n    delay(500);\n  }\n  // Normal sürüş\n  else {\n    motorL.run(150);\n    motorR.run(150);\n    led.setColor(0, 0, 255, 0);  // Yeşil\n    led.show();\n  }\n}\n```\n\nBu yaklaşımda çizgi sensörü masa kenarı/uçurum tespiti, ultrasonik sensör engel tespiti yapar.")

add("mblock","lise","mBot'ta timer interrupt kullanarak çoklu görev (multitasking) nasıl yapılır?","Arduino modunda millis() ile multitasking:\n\n```cpp\n#include <MeMCore.h>\n\nMeUltrasonicSensor ultra(PORT_3);\nMeDCMotor motorL(M1);\nMeDCMotor motorR(M2);\nMeRGBLed led(0, 2);\nMeBuzzer buzzer;\n\nunsigned long oncekiLed = 0;\nunsigned long oncekiSensor = 0;\nunsigned long oncekiBuzzer = 0;\nbool ledDurum = false;\nfloat sonMesafe = 100;\n\nvoid setup() {\n  Serial.begin(9600);\n}\n\nvoid loop() {\n  unsigned long simdi = millis();\n  \n  // Görev 1: LED yanıp sönme (500ms)\n  if (simdi - oncekiLed >= 500) {\n    oncekiLed = simdi;\n    ledDurum = !ledDurum;\n    if (ledDurum) led.setColor(0, 0, 0, 255);\n    else led.setColor(0, 0, 0, 0);\n    led.show();\n  }\n  \n  // Görev 2: Mesafe okuma (200ms)\n  if (simdi - oncekiSensor >= 200) {\n    oncekiSensor = simdi;\n    sonMesafe = ultra.distanceCm();\n    if (sonMesafe < 20) {\n      motorL.run(0); motorR.run(0);\n    } else {\n      motorL.run(120); motorR.run(120);\n    }\n  }\n  \n  // Görev 3: Yakınlık uyarı bip (1000ms)\n  if (simdi - oncekiBuzzer >= 1000 && sonMesafe < 30) {\n    oncekiBuzzer = simdi;\n    buzzer.tone(1000, 100);\n  }\n}\n```\n\ndelay() yerine millis() kullanarak LED, sensör ve buzzer aynı anda bağımsız çalışır.")

add("mblock","lise","mBot ile state machine (durum makinesi) tasarım deseni nasıl uygulanır?","Farklı davranış modları için state machine:\n\n```cpp\n#include <MeMCore.h>\n\nenum RobotDurum { KESFET, ENGEL_KACIS, CIZGI_TAKIP, BEKLE };\nRobotDurum durum = KESFET;\n\nMeUltrasonicSensor ultra(PORT_3);\nMeLineFollower line(PORT_2);\nMeDCMotor motorL(M1);\nMeDCMotor motorR(M2);\nunsigned long durumZamani = 0;\n\nvoid setup() { Serial.begin(9600); }\n\nvoid loop() {\n  float mesafe = ultra.distanceCm();\n  int cizgi = line.readSensors();\n  \n  switch(durum) {\n    case KESFET:\n      motorL.run(130); motorR.run(130);\n      if (mesafe < 20) { durum = ENGEL_KACIS; durumZamani = millis(); }\n      if (cizgi != 3) { durum = CIZGI_TAKIP; }\n      break;\n      \n    case ENGEL_KACIS:\n      motorL.run(-120); motorR.run(120);\n      if (millis() - durumZamani > 800) { durum = KESFET; }\n      break;\n      \n    case CIZGI_TAKIP:\n      if (cizgi == 0) { motorL.run(100); motorR.run(100); }\n      else if (cizgi == 1) { motorL.run(60); motorR.run(100); }\n      else if (cizgi == 2) { motorL.run(100); motorR.run(60); }\n      else { durum = KESFET; }\n      break;\n      \n    case BEKLE:\n      motorL.run(0); motorR.run(0);\n      break;\n  }\n}\n```\n\nState machine ile robot davranışlarını modüler ve düzenli tutabilirsin. Her durumun giriş/çıkış koşulları bellidir.")

# --- robotik/ilkokul: 3 → 6 (3 eksik) ---
add("robotik","ilkokul","Robotların kullandığı motorlar hangi türlerdir?","Robotlarda kullanılan temel motor türleri:\n\n**1. DC Motor:**\n- Sürekli döner, hızlıdır\n- Tekerleklerde kullanılır\n- İleri ve geri gidebilir\n\n**2. Servo Motor:**\n- Belirli bir açıya döner (0-180°)\n- Robot kollarında, kapılarda kullanılır\n- Çok hassas hareket eder\n\n**3. Step Motor:**\n- Adım adım döner\n- 3D yazıcılarda kullanılır\n- Çok hassas ama yavaştır\n\n**Hangi motor nerede?**\n- Arabanın tekerlekleri → DC motor\n- Robot kolun parmakları → Servo motor\n- Yazıcının kafası → Step motor\n\nMotorlar robotun kasları gibidir — beyinden (Arduino) gelen komutlarla hareket eder!")

add("robotik","ilkokul","Basit bir kutu robotun gövdesi nasıl yapılır?","Kartondan basit robot gövdesi yapımı:\n\n**Malzemeler:**\n- Ayakkabı kutusu veya karton\n- 2 adet DC motor\n- 2 tekerlek (şişe kapağı olabilir)\n- 1 sarıcı tekerlek (arkada denge için)\n- Pil yuvası\n- Yapıştırıcı ve bant\n\n**Adımlar:**\n1. Kutunun alt iki yanına motor için delik aç\n2. Motorları yapıştır, tekerlekleri tak\n3. Arkaya sarıcı tekerlek veya bilye ekle\n4. Üste Arduino ve breadboard'u yerleştir\n5. Pil yuvasını bağla\n6. Kabloları düzenle\n\n**Dikkat:**\n- Motorlar simetrik olmalı (düz gitsin)\n- Ağırlık merkezi ortada olmalı\n- Kabloları bantla sabitle yoksa kopabilir")

add("robotik","ilkokul","Uzaktan kumandalı robot ile otonom robot arasındaki fark nedir?","**Uzaktan Kumandalı Robot:**\n- İnsan kontrol eder (kumanda, telefon ile)\n- Robot kendi kararını veremez\n- Kumandaya bağımlıdır\n- Örnek: Oyuncak araba, drone yarışı\n\n**Otonom Robot:**\n- Kendi kararlarını verir\n- Sensörlerle çevreyi algılar\n- Program sayesinde ne yapacağını bilir\n- İnsan müdahalesi gerekmez\n- Örnek: Süpürge robot, Mars gezgini\n\n**Hangisi daha zor?**\nOtonom robot yapmak çok daha zordur çünkü robotun her durumu düşünmesi ve karar vermesi gerekir. Ama bir kere programlandı mı kendi başına çalışabilir!\n\n**İpucu:** Önce uzaktan kumandalı robot yap, sonra sensör ekleyerek otonom hale getir.")

# --- robotik/ortaokul: 4 → 6 (2 eksik) ---
add("robotik","ortaokul","Robotik yarışmalarda kullanılan temel strateji ve taktikler nelerdir?","Robotik yarışmalarda kazanma stratejileri:\n\n**Çizgi İzleme Yarışması:**\n- Sensör sayısını artır (5-8 sensör daha hassas)\n- PID kontrol kullan (sallanmayı azaltır)\n- Virajlarda yavaşla, düzlükte hızlan\n- Keskin viraj algılama: tüm sensörler beyazsa dur ve ara\n\n**Sumo Robot:**\n- Düşük ağırlık merkezi (devrilmemek için)\n- Ön tampon eğimli olsun (rakibi kaldır)\n- İlk hamle: saldır veya bekle stratejisi\n- Kenar algılama çok hızlı olmalı\n\n**Engelden Kaçma:**\n- Sağ duvar takibi algoritması (labirente girersen sağ duvara yapış)\n- Çoklu sensör kullan (ön + yan)\n- Harita çıkarma: geçtiğin yerleri hatırla\n\n**Genel İpuçları:**\n- Pil seviyesi düşünce robot yavaşlar — tam şarj ile yarış\n- Test, test, test — yarıştan önce 50+ deneme yap")

add("robotik","ortaokul","Robotik projede güç kaynağı seçimi nasıl yapılır?","Robot projelerinde doğru güç kaynağı seçmek kritiktir:\n\n**Pil türleri:**\n- **AA Alkalin (1.5V):** Ucuz, kolay bulunur ama çabuk biter. Hafif projeler için.\n- **Li-Po (3.7V):** Hafif, yüksek akım verebilir. Drone ve yarış robotları için.\n- **Li-ion 18650 (3.7V):** Şarj edilebilir, uzun ömürlü. Genel robotik için.\n- **9V pil:** Arduino beslemek için uygun ama motorlar için yetersiz.\n\n**Seçim kriterleri:**\n- Motor sayısı × motor akımı = gereken toplam akım\n- Gerilim: motorların çalışma voltajına uygun olmalı\n- Kapasite (mAh): ne kadar büyükse o kadar uzun çalışır\n- Ağırlık: yarış robotunda her gram önemli\n\n**Altın kural:** Arduino ve motorları ayrı beslemelisin. Motorlar çok akım çektiğinde Arduino'nun voltajı düşer ve reset atabilir. Ayrı pil veya regülatör kullan.")

# --- robotik/lise: 4 → 6 (2 eksik) ---
add("robotik","lise","Robotik sistemlerde ROS (Robot Operating System) nedir ve temel kavramları açıkla.","ROS, robot yazılımı geliştirmek için açık kaynaklı bir çerçevedir.\n\n**Temel kavramlar:**\n- **Node:** Bağımsız çalışan program (sensör okuma, motor kontrol)\n- **Topic:** Node'lar arası veri kanalı (publish/subscribe)\n- **Message:** Topic üzerinden gönderilen veri yapısı\n- **Service:** İstek-cevap tabanlı iletişim (tek seferlik işlemler)\n- **Package:** İlgili kodları gruplayan klasör\n\n**Örnek mimari:**\n```\n[LiDAR Node] --/scan--> [SLAM Node] --/map--> [Navigation Node]\n[Kamera Node] --/image--> [Nesne Algılama Node]\n[Motor Node] <--/cmd_vel-- [Navigation Node]\n```\n\n**Temel komutlar:**\n- `roscore` — ROS master başlat\n- `rosrun paket node` — Node çalıştır\n- `rostopic list` — Aktif topic'leri listele\n- `rostopic echo /scan` — Topic verisini görüntüle\n\n**Neden ROS?** Tekerlekleri yeniden icat etme — SLAM, navigasyon, görüntü işleme paketleri hazır.")

add("robotik","lise","Otonom robotlarda yol planlama (path planning) algoritmaları nelerdir?","Yol planlama, robotun başlangıçtan hedefe engelsiz yol bulmasıdır.\n\n**1. A* (A-Star):**\n```python\ndef a_star(grid, baslangic, hedef):\n    acik = [(0, baslangic)]  # (f_score, konum)\n    kapali = set()\n    g_score = {baslangic: 0}\n    gelinen = {}\n    \n    while acik:\n        _, mevcut = heapq.heappop(acik)\n        if mevcut == hedef:\n            return yolu_olustur(gelinen, mevcut)\n        kapali.add(mevcut)\n        for komsu in komsulari_bul(grid, mevcut):\n            if komsu in kapali: continue\n            yeni_g = g_score[mevcut] + 1\n            if yeni_g < g_score.get(komsu, float('inf')):\n                g_score[komsu] = yeni_g\n                f = yeni_g + heuristic(komsu, hedef)\n                heapq.heappush(acik, (f, komsu))\n                gelinen[komsu] = mevcut\n```\n\n**2. RRT (Rapidly-exploring Random Tree):**\nRastgele noktalar seçerek ağaç büyütür. Yüksek boyutlu uzaylarda etkili.\n\n**3. Dijkstra:** A*'ın heuristic'siz hali, en kısa yolu garanti eder.\n\n**Karşılaştırma:** A* bilinçli arama (heuristic ile hızlı), RRT yüksek boyutlu/kol planlama, Dijkstra ağırlıklı graflarda optimal.")

